queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?customer_service_representatives a :Customer_Service_Representatives .
    ?customer_service_representatives p:name ?fullname .
    ?customer_service_representatives p:skills ?skills_f .
    FILTER(STR(?skills_f) = "Proactivity")
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?call_center_agents a :Call_Center_Agents .
    ?call_center_agents p:name ?fullname .
    ?call_center_agents p:skills ?skills_f .
    FILTER(STR(?skills_f) = "Proactivity")
    BIND(?fullname AS ?o0)
  }
}

